import "sort"

func IntervalScheduling(arr []int) int {
	n := arr[0]
	type Interval struct{ start, end int }
	intervals := make([]Interval, n)
	for i := 0; i < n; i++ {
		intervals[i] = Interval{arr[1+2*i], arr[1+2*i+1]}
	}

	sort.Slice(intervals, func(i, j int) bool {
		return intervals[i].end < intervals[j].end
	})

	count := 0
	lastEnd := -1
	for _, iv := range intervals {
		if iv.start >= lastEnd {
			count++
			lastEnd = iv.end
		}
	}

	return count
}

import java.util.Arrays;

public class IntervalScheduling {

    public static int intervalScheduling(int[] arr) {
        int n = arr[0];
        int[][] intervals = new int[n][2];
        for (int i = 0; i < n; i++) {
            intervals[i][0] = arr[1 + 2 * i];
            intervals[i][1] = arr[1 + 2 * i + 1];
        }

        Arrays.sort(intervals, (a, b) -> a[1] - b[1]);

        int count = 0;
        int lastEnd = -1;

        for (int[] interval : intervals) {
            if (interval[0] >= lastEnd) {
                count++;
                lastEnd = interval[1];
            }
        }

        return count;
    }
}

fun intervalScheduling(arr: IntArray): Int {
    val n = arr[0]
    data class Interval(val start: Int, val end: Int)

    val intervals = Array(n) { Interval(arr[1 + 2 * it], arr[1 + 2 * it + 1]) }
    val sorted = intervals.sortedBy { it.end }

    var count = 0
    var lastEnd = -1
    for (iv in sorted) {
        if (iv.start >= lastEnd) {
            count++
            lastEnd = iv.end
        }
    }

    return count
}

pub fn interval_scheduling(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let mut intervals: Vec<(i32, i32)> = (0..n)
        .map(|i| (arr[1 + 2 * i], arr[1 + 2 * i + 1]))
        .collect();

    intervals.sort_by_key(|iv| iv.1);

    let mut count = 0;
    let mut last_end = -1;
    for (start, end) in &intervals {
        if *start >= last_end {
            count += 1;
            last_end = *end;
        }
    }

    count
}

object IntervalScheduling {

  def intervalScheduling(arr: Array[Int]): Int = {
    val n = arr(0)
    val intervals = Array.tabulate(n)(i => (arr(1 + 2 * i), arr(1 + 2 * i + 1)))
    val sorted = intervals.sortBy(_._2)

    var count = 0
    var lastEnd = -1
    for ((start, end) <- sorted) {
      if (start >= lastEnd) {
        count += 1
        lastEnd = end
      }
    }

    count
  }
}

func intervalScheduling(_ arr: [Int]) -> Int {
    let n = arr[0]
    var intervals: [(start: Int, end: Int)] = []
    for i in 0..<n {
        intervals.append((arr[1 + 2 * i], arr[1 + 2 * i + 1]))
    }

    intervals.sort { $0.end < $1.end }

    var count = 0
    var lastEnd = -1
    for iv in intervals {
        if iv.start >= lastEnd {
            count += 1
            lastEnd = iv.end
        }
    }

    return count
}

export function intervalScheduling(arr: number[]): number {
    const n = arr[0];
    const intervals: [number, number][] = [];
    for (let i = 0; i < n; i++) {
        intervals.push([arr[1 + 2 * i], arr[1 + 2 * i + 1]]);
    }

    intervals.sort((a, b) => a[1] - b[1]);

    let count = 0;
    let lastEnd = -1;
    for (const [start, end] of intervals) {
        if (start >= lastEnd) {
            count++;
            lastEnd = end;
        }
    }

    return count;
}
